Vtiger_Detail_Js("OSSMailView_Detail_Js",{printMail:function(){var t=$("#subject").val(),e=$("#from_email").val(),r=$("#to_email").val(),a=$("#cc_email").val(),i=jQuery("#createdtime").val(),n=$("#content").html(),l=window.open();l.document.write("<b>"+app.vtranslate("Subject")+": "+t+"</b><br>"),l.document.write("<br>"+app.vtranslate("From")+": "+e+"<br>"),l.document.write(app.vtranslate("To")+" :"+r+"<br>"),null!=a&&l.document.write(app.vtranslate("CC")+": "+a+"<br>"),l.document.write(app.vtranslate("Date")+": "+i+"<br>"),l.document.write("<hr/>"+n+"<br>"),l.print()}},{registerEvents:function(){this._super();var t=jQuery("div.detailViewToolbar");Vtiger_Index_Js.registerMailButtons(t)}});